from dataclasses import dataclass, field
from typing import Literal


PILLAR_WEIGHTS = {
    "api_availability": 0.25,
    "model_capability": 0.25,
    "latency_profile": 0.20,
    "infra_readiness": 0.20,
    "security_posture": 0.10,
}


@dataclass
class PillarScore:
    name: str
    score: float          # 0–100
    evidence: str         # brief justification
    blockers: list[str] = field(default_factory=list)


@dataclass
class FeasibilityAssessment:
    project_name: str
    pillar_scores: list[PillarScore]

    def weighted_score(self) -> float:
        total = 0.0
        for p in self.pillar_scores:
            weight = PILLAR_WEIGHTS.get(p.name, 0.0)
            total += p.score * weight
        return round(total, 1)

    def recommendation(self) -> Literal["proceed", "conditional", "no-go"]:
        score = self.weighted_score()
        if score >= 80:
            return "proceed"
        elif score >= 60:
            return "conditional"
        return "no-go"

    def critical_blockers(self) -> list[str]:
        """Collect blockers from pillars scoring below 60."""
        blockers = []
        for p in self.pillar_scores:
            if p.score < 60:
                blockers.extend([
                    f"[{p.name}] {b}" for b in p.blockers
                ])
        return blockers

    def report(self) -> str:
        lines = [
            f"=== Feasibility Assessment: {self.project_name} ===",
            f"Weighted Score: {self.weighted_score()}/100",
            f"Recommendation: {self.recommendation().upper()}",
            "",
            "Pillar Breakdown:",
        ]
        for p in self.pillar_scores:
            w = PILLAR_WEIGHTS.get(p.name, 0.0)
            lines.append(
                f"  {p.name:<25} {p.score:>5.0f}/100  (weight {w:.0%})  {p.evidence}"
            )
        blockers = self.critical_blockers()
        if blockers:
            lines += ["", "Critical Blockers:"]
            lines += [f"  • {b}" for b in blockers]
        return "\n".join(lines)
